import { describe, expect, it } from 'vitest';
import { buildPostMutationRequirement } from '../../core/agent/post-mutation.js';

describe('buildPostMutationRequirement', () => {
  it('returns an empty string when no post-mutation work is pending', () => {
    expect(buildPostMutationRequirement({
      pendingVerification: false,
      pendingChangeReview: false,
    })).toBe('');
  });

  it('can still note existing verification when requested', () => {
    const message = buildPostMutationRequirement({
      pendingVerification: false,
      pendingChangeReview: false,
      verificationCommands: ['yarn test'],
      noteExistingVerification: true,
    });

    expect(message).toContain('verification already captured: yarn test');
  });
});
